+++ b/llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp
@@ -504,6 +504,15 @@ static bool isDeadRecipe(VPRecipeBase &R) {
   if (R.mayHaveSideEffects())
     return false;

+  // Don't remove comparison instructions that might be used for control flow,
+  // even if they appear to have no users in the VPlan.
+  if (auto *VPInst = dyn_cast<VPInstruction>(&R)) {
+    if (VPInst->getOpcode() == Instruction::ICmp ||
+        VPInst->getOpcode() == Instruction::FCmp) {
+      return false;
+    }
+  }
+
   // Recipe is dead if no user keeps the recipe alive.
   return all_of(R.definedValues(),
                 [](VPValue *V) { return V->getNumUsers() == 0; });
