--- a/llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp
@@ -504,6 +504,28 @@ static bool isDeadRecipe(VPRecipeBase &R) {
   if (R.mayHaveSideEffects())
     return false;

+  // Don't remove recipes that are used in exit block computations, even if
+  // they appear to have no users in the VPlan.
+  if (auto *SingleDefR = dyn_cast<VPSingleDefRecipe>(&R)) {
+    if (Instruction *UI = SingleDefR->getUnderlyingInstr()) {
+      for (User *U : UI->users()) {
+        // If this instruction is used by a branch or is an induction variable
+        // increment that might be used in exit value computation, don't remove it.
+        if (isa<BranchInst>(U))
+          return false;
+        
+        // Check if this is an induction increment used in exit computation
+        if (auto *AddInst = dyn_cast<BinaryOperator>(U)) {
+          if (AddInst->getOpcode() == Instruction::Add) {
+            // This could be an induction increment, keep it to ensure correct
+            // exit value computation
+            return false;
+          }
+        }
+      }
+    }
+  }
+
   // Recipe is dead if no user keeps the recipe alive.
   return all_of(R.definedValues(),
                 [](VPValue *V) { return V->getNumUsers() == 0; });
